operation.add:
static $cyberpunks_shop_tpl_schema_add;
if (!isset($cyberpunks_shop_tpl_schema_add)) {
	$cyberpunks_shop_tpl_schema_add = true;
	$cyberpunks_shop_tpl_col = $this->db->query("SHOW COLUMNS FROM `" . DB_PREFIX . "product` LIKE 'cyberpunks_template'");
	if (!$cyberpunks_shop_tpl_col->num_rows) {
		$this->db->query("ALTER TABLE `" . DB_PREFIX . "product` ADD `cyberpunks_template` VARCHAR(255) NOT NULL DEFAULT ''");
	}
}

static $cyberpunks_shop_tpl_schema_edit;
if (!isset($cyberpunks_shop_tpl_schema_edit)) {
	$cyberpunks_shop_tpl_schema_edit = true;
	$cyberpunks_shop_tpl_col = $this->db->query("SHOW COLUMNS FROM `" . DB_PREFIX . "product` LIKE 'cyberpunks_template'");
	if (!$cyberpunks_shop_tpl_col->num_rows) {
		$this->db->query("ALTER TABLE `" . DB_PREFIX . "product` ADD `cyberpunks_template` VARCHAR(255) NOT NULL DEFAULT ''");
	}
}

if (isset($this->request->post['cyberpunks_template'])) {
	$data['cyberpunks_template'] = $this->request->post['cyberpunks_template'];
} elseif (!empty($product_info)) {
	$data['cyberpunks_template'] = isset($product_info['cyberpunks_template']) ? $product_info['cyberpunks_template'] : '';
} else {
	$data['cyberpunks_template'] = '';
}

$data['cyberpunks_template_options'] = array();
$cyberpunks_shop_tpl_seen = array();
$cyberpunks_shop_theme_root = DIR_CATALOG . 'view/theme/';
if (is_dir($cyberpunks_shop_theme_root)) {
	foreach (glob($cyberpunks_shop_theme_root . '*', GLOB_ONLYDIR) as $cyberpunks_shop_theme_dir) {
		$cyberpunks_shop_product_tpl = $cyberpunks_shop_theme_dir . '/template/product';
		if (!is_dir($cyberpunks_shop_product_tpl)) {
			continue;
		}
		foreach (glob($cyberpunks_shop_product_tpl . '/*.twig') as $cyberpunks_shop_tpl_file) {
			$cyberpunks_shop_tpl_key = 'product/' . basename($cyberpunks_shop_tpl_file, '.twig');
			if (!isset($cyberpunks_shop_tpl_seen[$cyberpunks_shop_tpl_key])) {
				$cyberpunks_shop_tpl_seen[$cyberpunks_shop_tpl_key] = true;
				$data['cyberpunks_template_options'][] = $cyberpunks_shop_tpl_key;
			}
		}
	}
	sort($data['cyberpunks_template_options']);
}

$cyberpunks_catalog_view_route = 'product/product';
if (!empty($product_info['cyberpunks_template'])) {
	$cyberpunks_catalog_view_route = preg_replace('/[^a-zA-Z0-9_\/]/', '', (string)$product_info['cyberpunks_template']);
}
if ($cyberpunks_catalog_view_route === '') {
	$cyberpunks_catalog_view_route = 'product/product';
}
$this->registry->set('cyberpunks_catalog_view_route', $cyberpunks_catalog_view_route);
if (is_file(DIR_SYSTEM . 'library/cyberpunks_shop_head_includes.php')) {
	require_once DIR_SYSTEM . 'library/cyberpunks_shop_head_includes.php';
	CyberpunksShopHeadIncludes::applyViewRules($this->registry, $cyberpunks_catalog_view_route);
}
